Code:
public String plusOut(String str, String word) {
    StringBuilder sb = new StringBuilder();
    int wordLength = word.length();
    int i = 0;
    while (i < str.length()) {
        int j = 0;
        while (j < wordLength && i + j < str.length()) {
            if (str.charAt(i + j) != word.charAt(j)) {
                break;
            }
            j++;
        }
        if (j == wordLength) {
            sb.append(word);
            i += wordLength;
        } else {
            sb.append('+');
            i++;
        }
    }
    return sb.toString();
}

